type RawRow = {
  tool_name: string
  tool_call_status: string
  trial: number
  latency_ms: number
  input_bytes: number
  output_bytes: number
}

function p50(values: number[]) {
  const sorted = [...values].sort((a, b) => a - b)
  return sorted[Math.floor(sorted.length / 2)]!
}

function summarize(rows: RawRow[]) {
  return [...new Set(rows.map((row) => `${row.tool_name}::${row.tool_call_status}`))]
    .map((key) => {
      const values = rows.filter((row) => `${row.tool_name}::${row.tool_call_status}` === key)
      const latencies = values.map((row) => row.latency_ms)
      return {
        tool_name: values[0]!.tool_name,
        tool_call_status: values[0]!.tool_call_status,
        runs: values.length,
        min_latency_ms: Math.min(...latencies),
        p50_latency_ms: p50(latencies),
        max_latency_ms: Math.max(...latencies),
        avg_latency_ms: Number((latencies.reduce((acc, item) => acc + item, 0) / latencies.length).toFixed(2)),
        avg_input_bytes: Number(
          (values.reduce((acc, item) => acc + item.input_bytes, 0) / values.length).toFixed(2),
        ),
        avg_output_bytes: Number(
          (values.reduce((acc, item) => acc + item.output_bytes, 0) / values.length).toFixed(2),
        ),
      }
    })
    .sort((a, b) => a.tool_name.localeCompare(b.tool_name))
}

async function runTrial(toolCase: (typeof toolCases)[number], trial: number) {
  return Effect.runPromise(
    provideTmpdirServer(
      ({ dir, llm }) =>
        Effect.gen(function* () {
          yield* Effect.promise(() => toolCase.setup(dir))
          yield* Effect.promise(() => toolCase.queue(llm, dir))
          const prompt = yield* SessionPrompt.Service
          const sessions = yield* Session.Service
          const bus = yield* Bus.Service
          const session = yield* sessions.create({
            title: `${toolCase.tool_name}-${trial}`,
            permission: [{ permission: "*", pattern: "*", action: "allow" }],
          })
          const seen = yield* Deferred.make<void>()
          let metric:
            | {
                tool_name: string
                tool_call_status: string
                latency_ms: number
                input_bytes: number
                output_bytes: number
              }
            | undefined
          const off = yield* bus.subscribeCallback(Metrics.ToolCall, (evt) => {
            if (evt.properties.sessionID !== session.id) return
            metric = evt.properties
            Deferred.doneUnsafe(seen, Effect.void)
          })

          yield* user(session.id, toolCase.prompt_text)
          const fiber = yield* prompt.loop({ sessionID: session.id }).pipe(Effect.forkChild)
          yield* Deferred.await(seen)
          const exit = yield* Fiber.await(fiber)
          off()
          if (Exit.isFailure(exit)) return yield* Effect.fail(Cause.squash(exit.cause))
          if (!metric) return yield* Effect.fail(new Error(`missing metric for ${toolCase.tool_name}`))
          return {
            tool_name: metric.tool_name,
            tool_call_status: metric.tool_call_status,
            latency_ms: metric.latency_ms,
            input_bytes: metric.input_bytes,
            output_bytes: metric.output_bytes,
          }
        }),
      { git: true, config: providerCfg },
    ).pipe(Effect.provide(runtime), Effect.scoped),
  )
}

const rows: RawRow[] = []
for (const toolCase of toolCases) {
  for (let trial = 1; trial <= toolCase.trials; trial++) {
    const row = await runTrial(toolCase, trial)
    if (row.tool_name !== toolCase.tool_name || row.tool_call_status !== toolCase.expected_status) {
      throw new Error(
        `unexpected metric for ${toolCase.tool_name}: got ${row.tool_name}/${row.tool_call_status}, expected ${toolCase.tool_name}/${toolCase.expected_status}`,
      )
    }
    rows.push({ ...row, trial })
  }
}

const summaryRows = summarize(rows)
