# Tool timing table
rows=[]
for line in (base/'mimocode-run3-qwen3xml.jsonl').read_text(errors='ignore').splitlines():
    try: o=json.loads(line)
    except Exception: continue
    if o.get('type')!='tool_use': continue
    p=o.get('part',{}); st=p.get('state') or {}; tm=st.get('time') or {}
    start=tm.get('start'); end=tm.get('end')
    rows.append({
        'idx':len(rows)+1,'tool':p.get('tool'),'status':st.get('status'),'start_ms':start,'end_ms':end,
