        'title':st.get('title') or p.get('title') or '',
        'input':json.dumps(st.get('input'),ensure_ascii=False)[:500],
        'output_preview':str(st.get('output',''))[:300].replace('\n','\\n')
    })
with open(out/'tool_calls.csv','w',newline='') as f:
    w=csv.DictWriter(f, fieldnames=list(rows[0].keys())); w.writeheader(); w.writerows(rows)
print('TOOL_TABLE', out/'tool_calls.csv')
print('TOOLS', len(rows), 'latency ms summary', {k: (min(v), statistics.median(v), max(v), sum(v)/len(v)) for k,v in {'all':[r['latency_ms'] for r in rows if r['latency_ms'] is not None]}.items()})
for r in rows: print('TOOLROW', r['idx'], r['tool'], r['status'], r['latency_ms'], r['title'], r['input'][:120])
# Proxy success request table from stream usage
reqs=[]
for sp in sorted((base/'proxy-qwen3xml').glob('*-stream.txt')):
    stem=sp.name.replace('-stream.txt','')
    rp=base/'proxy-qwen3xml'/f'{stem}-request.json'
    if not rp.exists(): continue
    r=json.load(open(rp)); body=r.get('body') or {}
    usage=None; finish=None; first_ms=None; last_ms=None
    for line in sp.read_text(errors='ignore').splitlines():
